WITH hate_comments AS 
 (SELECT c.profile_id AS profile_id, p.num_followers - cnt.num_comments::integer AS hate_factor
 FROM comment c JOIN publication p ON c.publication_id = p.id JOIN (
 SELECT publication_id, COUNT(DISTINCT comment_id) as num_comments
 FROM comment GROUP BY publication_id ORDER BY 1 DESC, visited_at ORDER BY 2 DESC
 ) cnt ON p.id = cnt.publication_id WHERE (c.annotation !~~ '*✍*' AND c.num_likes < 0)
 }
 SELECT profile_id, hate_factor FROM hate_comments ORDER BY hate_factor LIMIT 10;
